const mongoose = require('mongoose');

const UserSchema = new mongoose.Schema({
    username: {
        type: String,
        required: true,
        unique: true,
        trim: true,
        minlength: 3
    },
    password: {
        type: String,
        required: true
    },
    // Game State
    points: { type: Number, default: 1000 },
    energy: { type: Number, default: 100 },
    inventory: {
        banana: { type: Number, default: 0 },
        fish: { type: Number, default: 0 },
        clothes: { type: Number, default: 0 }
    },
    // Positional Data (Persisted optionally, mainly used for initial spawn)
    position: {
        x: { type: Number, default: 0 },
        y: { type: Number, default: 0 },
        z: { type: Number, default: 15 }
    },
    rotationY: { type: Number, default: 0 }
}, { timestamps: true });

module.exports = mongoose.model('User', UserSchema);

require('dotenv').config();
const express = require('express');
const mongoose = require('mongoose');
const http = require('http');
const { Server } = require('socket.io');
const cors = require('cors');
const bcrypt = require('bcrypt');
const jwt = require('jsonwebtoken');

const User = require('./models/User');

const app = express();
const server = http.createServer(app);

// Configure CORS for Vite Frontend
app.use(cors({
    origin: '*', // During dev you can leave it generic, or specify 'http://localhost:5173'
    methods: ['GET', 'POST', 'PUT']
}));
app.use(express.json());

const io = new Server(server, {
    cors: {
        origin: '*',
        methods: ["GET", "POST"]
    }
});

// Database connection
mongoose.connect(process.env.MONGO_URI)
    .then(() => console.log('✅ Connected to MongoDB Clusters'))
    .catch(err => console.error('❌ MongoDB Connection Error:', err));


// --- REST API ROUTES (AUTH) --- //

app.post('/api/signup', async (req, res) => {
    try {
        const { username, password } = req.body;
        if (!username || !password) return res.status(400).json({ error: 'Username and password required' });

        const existingUser = await User.findOne({ username });
        if (existingUser) return res.status(400).json({ error: 'Username already exists' });

        const hashedPassword = await bcrypt.hash(password, 10);
        const newUser = new User({ username, password: hashedPassword });
        await newUser.save();

        res.status(201).json({ message: 'User created successfully' });
    } catch (err) {
        res.status(500).json({ error: 'Server error during signup' });
    }
});

app.post('/api/login', async (req, res) => {
    try {
        const { username, password } = req.body;
        const user = await User.findOne({ username });

        if (!user) return res.status(400).json({ error: 'User not found' });

        const isMatch = await bcrypt.compare(password, user.password);
        if (!isMatch) return res.status(400).json({ error: 'Invalid credentials' });

        const token = jwt.sign({ userId: user._id, username: user.username }, process.env.JWT_SECRET, { expiresIn: '24h' });

        res.status(200).json({
            token,
            user: {
                username: user.username,
                points: user.points,
                energy: user.energy,
                inventory: user.inventory,
                position: user.position,
                rotationY: user.rotationY
            }
        });
    } catch (err) {
        res.status(500).json({ error: 'Server error during login' });
    }
});

// Save user state periodically (points, energy, inventory)
app.put('/api/save-state', async (req, res) => {
    try {
        const { username, points, energy, inventory, position, rotationY } = req.body;
        await User.findOneAndUpdate(
            { username },
            { $set: { points, energy, inventory, position, rotationY } }
        );
        res.status(200).json({ message: 'State saved' });
    } catch (err) {
        res.status(500).json({ error: 'Failed to save state' });
    }
});


// --- SOCKET.IO MULTIPLAYER LOGIC --- //

// Keep track of connected players in memory
const players = {};

io.on('connection', (socket) => {
    console.log(`🔌 New client connected: ${socket.id}`);

    // When a player first loads into the game after login
    socket.on('join_game', (userData) => {
        // Assign the socket id to this player's data
        players[socket.id] = {
            id: socket.id,
            username: userData.username,
            x: userData.position?.x || (Math.random() * 20 - 10), // Randomize spawn slightly around center
            y: userData.position?.y || 0,
            z: userData.position?.z || 15,
            rotationY: userData.rotationY || 0,
            animating: false // true if walking
        };

        // Tell this new client about all existing players currently in the lobby
        socket.emit('current_players', players);

        // Tell all OTHER clients that a new player joined
        socket.broadcast.emit('player_joined', players[socket.id]);
        console.log(`🎮 Player joined: ${userData.username} at ${socket.id}`);
    });

    // When a player moves, broadcast their new position
    socket.on('player_move', (moveData) => {
        if (players[socket.id]) {
            players[socket.id].x = moveData.x;
            players[socket.id].y = moveData.y;
            players[socket.id].z = moveData.z;
            players[socket.id].rotationY = moveData.rotationY;
            players[socket.id].animating = moveData.animating; // Send true if they are currently generating movement

            // Broadcast to everyone else
            socket.broadcast.emit('player_moved', players[socket.id]);
        }
    });

    // Cleanup when player disconnects
    socket.on('disconnect', () => {
        console.log(`❌ Client disconnected: ${socket.id}`);
        if (players[socket.id]) {
            io.emit('player_left', socket.id);
            delete players[socket.id];
        }
    });
});


const PORT = process.env.PORT || 5000;
server.listen(PORT, () => {
    console.log(`🚀 Multiplayer Backend running on port ${PORT}`);
});

import React, { useRef, useEffect, useMemo } from 'react';
import * as THREE from 'three';
import { addObstacle, removeObstacle } from '../utils/collisionStore';
import { makeTextTexture } from './constants';

export function Bank({ x, z, rotationY = 0 }) {
    const bankRef = useRef();
    useEffect(() => {
        if (bankRef.current) addObstacle(bankRef.current);
        return () => { if (bankRef.current) removeObstacle(bankRef.current); };
    }, []);

    const signTex = useMemo(() => new THREE.CanvasTexture(makeTextTexture("CITY BANK", "#ffd700", "#000000")), []);

    return (
        <group ref={bankRef} position={[x, 0, z]} rotation={[0, rotationY, 0]}>
            <mesh position={[0, 0.3, 0]} castShadow>
                <boxGeometry args={[16, 0.6, 12]} />
                <meshLambertMaterial color={0xffffff} />
            </mesh>
            <mesh position={[0, 0.15, 0]}>
                <boxGeometry args={[18, 0.3, 14]} />
                <meshLambertMaterial color={0xffffff} />
            </mesh>
            <mesh position={[0, 4.6, -1]} castShadow>
                <boxGeometry args={[14, 8, 8]} />
                <meshLambertMaterial color={0xeeeeee} />
            </mesh>

            {[-4, 4].map(i => (
                <mesh key={`win-${i}`} position={[i, 4.6, -1]}>
                    <boxGeometry args={[2, 4, 8.2]} />
                    <meshLambertMaterial color={0x87CEFA} />
                </mesh>
            ))}

            {[-6, -3, 3, 6].map(i => (
                <mesh key={`pillar-${i}`} position={[i, 4.6, 4]} castShadow>
                    <cylinderGeometry args={[0.6, 0.6, 8, 32]} />
                    <meshLambertMaterial color={0xffffff} />
                </mesh>
            ))}

            <mesh position={[0, 10.6, 1.5]} rotation={[0, Math.PI / 4, 0]} castShadow>
                <coneGeometry args={[12, 4, 4]} />
                <meshLambertMaterial color={0xffffff} />
            </mesh>

            <mesh position={[0, 8, 4.5]}>
                <boxGeometry args={[8, 1.5, 0.4]} />
                <meshLambertMaterial attach="material-0" color={0xffd700} />
                <meshLambertMaterial attach="material-1" color={0xffd700} />
                <meshLambertMaterial attach="material-2" color={0xffd700} />
                <meshLambertMaterial attach="material-3" color={0xffd700} />
                <meshLambertMaterial attach="material-4" map={signTex} />
                <meshLambertMaterial attach="material-5" color={0xffd700} />
            </mesh>

            <mesh position={[0, 2.6, 3.1]}>
                <boxGeometry args={[3, 4, 0.2]} />
                <meshLambertMaterial color={0x87CEFA} />
            </mesh>

            {[-7, 7].map(i => (
                <mesh key={`bush-${i}`} position={[i, 1, 6]}>
                    <sphereGeometry args={[1, 8, 8]} />
                    <meshLambertMaterial color={0x228b22} />
                </mesh>
            ))}
        </group>
    );
}

import React, { useRef, useEffect, useState, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { addWalkable, addObstacle, removeWalkable, removeObstacle } from '../utils/collisionStore';

export function Ground() {
    const groundRef = useRef();

    useEffect(() => {
        if (groundRef.current) addWalkable(groundRef.current);
        return () => { if (groundRef.current) removeWalkable(groundRef.current); };
    }, []);

    return (
        <mesh ref={groundRef} position={[0, -1, 0]} receiveShadow>
            <boxGeometry args={[340, 2, 340]} />
            <meshLambertMaterial color={0x7cfc00} />
        </mesh>
    );
}

export function River() {
    const waterRef = useRef();
    const baseRef = useRef();
    const bank1Ref = useRef();
    const bank2Ref = useRef();

    const [geometry] = useState(() => {
        const geo = new THREE.PlaneGeometry(350, 14, 100, 6);
        geo.rotateX(-Math.PI / 2);
        const pos = geo.attributes.position;
        geo.userData.origY = new Float32Array(pos.count);
        for (let i = 0; i < pos.count; i++) {
            geo.userData.origY[i] = pos.getY(i);
        }
        return geo;
    });

    useEffect(() => {
        if (baseRef.current) addWalkable(baseRef.current);
        if (bank1Ref.current) addWalkable(bank1Ref.current);
        if (bank2Ref.current) addWalkable(bank2Ref.current);

        return () => {
            if (baseRef.current) removeWalkable(baseRef.current);
            if (bank1Ref.current) removeWalkable(bank1Ref.current);
            if (bank2Ref.current) removeWalkable(bank2Ref.current);
        };
    }, []);

    return (
        <group position={[0, 0, 0]}>
            <RiverBed />
            <mesh ref={waterRef} geometry={geometry} position={[0, 0.2, 0]}>
                <meshPhysicalMaterial
                    color={0x00aaff}
                    transparent
                    opacity={0.75}
                    roughness={0.1}
                    metalness={0.2}
                    clearcoat={1.0}
                />
            </mesh>
            <RiverFishes />
        </group>
    );
}

function RiverBed() {
    const baseRef = useRef();
    const bank1Ref = useRef();
    const bank2Ref = useRef();

    useEffect(() => {
        if (baseRef.current) addWalkable(baseRef.current);
        if (bank1Ref.current) addWalkable(bank1Ref.current);
        if (bank2Ref.current) addWalkable(bank2Ref.current);

        return () => {
            if (baseRef.current) removeWalkable(baseRef.current);
            if (bank1Ref.current) removeWalkable(bank1Ref.current);
            if (bank2Ref.current) removeWalkable(bank2Ref.current);
        };
    }, []);

    return (
        <>
            <mesh ref={baseRef} position={[0, -0.1, 0]} receiveShadow>
                <boxGeometry args={[350, 0.5, 14]} />
                <meshPhongMaterial color={0x00bfff} transparent opacity={0.85} shininess={100} />
            </mesh>
            <mesh ref={bank1Ref} position={[0, 0.15, 7.5]}>
                <boxGeometry args={[350, 0.2, 1.5]} />
                <meshLambertMaterial color={0xdeb887} />
            </mesh>
            <mesh ref={bank2Ref} position={[0, 0.15, -7.5]}>
                <boxGeometry args={[350, 0.2, 1.5]} />
                <meshLambertMaterial color={0xdeb887} />
            </mesh>
        </>
    );
}

function Fish({ index }) {
    const fishRef = useRef();
    const dir = (index % 2 === 0) ? 1 : -1;
    const fx = -160 + (index * 8);
    const fz = -5 + (index % 4) * 3;
    const speed = (0.05 + (index % 3) * 0.02) * dir;

    // In React 18 / R3F useFrame scales time with elapsed / delta
    useFrame(() => {
        if (fishRef.current) {
            fishRef.current.position.x += speed * 0.8; // scaled a bit
            if (dir === 1 && fishRef.current.position.x > 160) fishRef.current.position.x = -160;
            if (dir === -1 && fishRef.current.position.x < -160) fishRef.current.position.x = 160;
        }
    });

    return (
        <group ref={fishRef} position={[fx, 0.05, fz]} rotation={[0, dir === -1 ? Math.PI : 0, 0]}>
            <mesh scale={[1.5, 0.8, 0.4]}>
                <sphereGeometry args={[0.3, 8, 4]} />
                <meshLambertMaterial color={0xff8c00} />
            </mesh>
            <mesh position={[-0.4, 0, 0]} rotation={[0, 0, -Math.PI / 2]}>
                <coneGeometry args={[0.2, 0.4, 3]} />
                <meshLambertMaterial color={0xff8c00} />
            </mesh>
        </group>
    );
}

function RiverFishes() {
    return (
        <>
            {Array.from({ length: 40 }).map((_, i) => (
                <Fish key={`fish-${i}`} index={i} />
            ))}
        </>
    );
}

export function Roads() {
    const groundSize = 340;
    const streetsZ = [25, 45, 65, 85, 105, 125, 145, -25, -45, -65, -85, -105, -125, -145];

    // Convert hooks to refs inside a sub-component for proper adding, or use multiple refs
    return (
        <group>
            <Road piece={[6, 0.05, groundSize]} pos={[-15, 0.02, 0]} />
            <Road piece={[6, 0.05, groundSize]} pos={[15, 0.02, 0]} />
            {streetsZ.map(z => (
                <Road key={`road-z-${z}`} piece={[groundSize, 0.05, 4]} pos={[0, 0.02, z]} />
            ))}
        </group>
    );
}

function Road({ piece, pos }) {
    const ref = useRef();
    useEffect(() => {
        if (ref.current) addWalkable(ref.current);
        return () => { if (ref.current) removeWalkable(ref.current); };
    }, []);
    return (
        <mesh ref={ref} position={pos} receiveShadow>
            <boxGeometry args={piece} />
            <meshLambertMaterial color={0x95a5a6} />
        </mesh>
    );
}

export function Bridge({ x }) {
    const bridgeRef = useRef();
    const planksRef = useRef();
    const railsRef = useRef();

    useEffect(() => {
        if (planksRef.current) addWalkable(planksRef.current);
        if (railsRef.current) addObstacle(railsRef.current);
        return () => {
            if (planksRef.current) removeWalkable(planksRef.current);
            if (railsRef.current) removeObstacle(railsRef.current);
        };
    }, []);

    const planks = [];
    let pIndex = 0;
    for (let z = -7.5; z <= 7.5; z += 1.0) {
        planks.push(
            <mesh
                key={`plank-${z}`}
                position={[0, 0.4, z]}
                rotation={[0, ((pIndex % 3) - 1) * 0.05, ((pIndex % 2) - 0.5) * 0.05]}
            >
                <boxGeometry args={[5.5, 0.2, 0.8]} />
                <meshLambertMaterial color={0x8b5a2b} />
            </mesh>
        );
        pIndex++;
    }

    return (
        <group position={[x, 0.5, 0]}>
            <group ref={planksRef}>
                {planks}
            </group>
            <group ref={railsRef}>
                {[-1, 1].map(side => (
                    <mesh key={`rail-${side}`} position={[side * 2.5, 1.2, 0]}>
                        <boxGeometry args={[0.5, 1.5, 16]} />
                        <meshLambertMaterial color={0x4a2e15} />
                    </mesh>
                ))}
            </group>
        </group>
    );
}

export function Cloud({ cx, cz, i }) {
    const cloudRef = useRef();
    const subClouds = [];
    const fixedHeight = 40 + (i % 5) * 5;

    for (let j = 0; j < 4; j++) {
        const ox = (j % 2 === 0) ? 2 : -2;
        const oy = (j > 1) ? 1 : -1;
        const oz = (j % 3 === 0) ? 2 : -2;
        const subScale = 1.0 + (j % 3) * 0.2;
        subClouds.push(
            <mesh key={`subc-${j}`} position={[ox, oy, oz]} scale={[subScale, subScale, subScale]}>
                <sphereGeometry args={[2, 8, 8]} />
                <meshLambertMaterial color={0xffffff} />
            </mesh>
        );
    }

    useFrame(() => {
        if (cloudRef.current) {
            cloudRef.current.position.x += 0.05 * (60 / 1000) * 16.6; // normalized speed
            if (cloudRef.current.position.x > 200) cloudRef.current.position.x = -200;
        }
    });

    return (
        <group ref={cloudRef} position={[cx, fixedHeight, cz]}>
            {subClouds}
        </group>
    );
}

import React, { useRef, useEffect } from 'react';
import { useFrame } from '@react-three/fiber';
import { addObstacle, removeObstacle } from '../utils/collisionStore';

export function Factory({ x, z, rotationY = 0 }) {
    const factoryRef = useRef();
    useEffect(() => {
        if (factoryRef.current) addObstacle(factoryRef.current);
        return () => { if (factoryRef.current) removeObstacle(factoryRef.current); };
    }, []);

    const teeth = [];
    for (let i = -9; i <= 9; i += 6) {
        teeth.push(
            <mesh key={`tooth-${i}`} position={[i, 13.25, 0]} rotation={[0, Math.PI / 4, 0]} scale={[1.5, 1, 5.6]} castShadow>
                <coneGeometry args={[3, 2.5, 4]} />
                <meshLambertMaterial color={0x555555} />
            </mesh>
        );
    }

    const chimneys = [];
    for (let i = -7; i <= 7; i += 7) {
        chimneys.push(
            <group key={`chim-${i}`}>
                <mesh position={[i, 15, -4]} castShadow>
                    <cylinderGeometry args={[1, 1.5, 14, 16]} />
                    <meshLambertMaterial color={0x333333} />
                </mesh>
                {Array.from({ length: 5 }).map((_, j) => (
                    <Smoke key={`smoke - ${j} `} x={i} y={22 + j * 2} z={-4} j={j} />
                ))}
            </group>
        );
    }

    return (
        <group ref={factoryRef} position={[x, 0, z]} rotation={[0, rotationY, 0]}>
            <mesh position={[0, 6, 0]} castShadow>
                <boxGeometry args={[24, 12, 16]} />
                <meshLambertMaterial color={0x8b3a3a} />
            </mesh>
            {teeth}
            {chimneys}
            {[-11, 11].map(i => (
                <mesh key={`pipe - ${i} `} position={[i, 6, 8.5]}>
                    <cylinderGeometry args={[0.5, 0.5, 12]} />
                    <meshLambertMaterial color={0x999999} />
                </mesh>
            ))}
            <mesh position={[0, 3, 8.1]}>
                <boxGeometry args={[6, 6, 0.3]} />
                <meshLambertMaterial color={0x333333} />
            </mesh>
            <mesh position={[0, 6.25, 8.1]}>
                <boxGeometry args={[6.4, 0.5, 0.4]} />
                <meshLambertMaterial color={0xffd700} />
            </mesh>
        </group>
    );
}

function Smoke({ x, y, z, j }) {
    const smokeRef = useRef();
    const baseY = 22;
    const speed = 0.04 + (j * 0.01);

    useFrame(() => {
        if (smokeRef.current) {
            smokeRef.current.position.y += speed * 0.5; // Adjusted speed for R3F mapping
            let heightDiff = smokeRef.current.position.y - baseY;
            const scaleVal = 1 + heightDiff * 0.12;
            smokeRef.current.scale.setScalar(scaleVal);
            smokeRef.current.material.opacity = Math.max(0, 0.8 - heightDiff * 0.08);

            if (heightDiff > 10) {
                smokeRef.current.position.y = baseY;
                smokeRef.current.scale.setScalar(1);
                smokeRef.current.material.opacity = 0.8;
            }
        }
    });

    return (
        <mesh ref={smokeRef} position={[x, y, z]}>
            <sphereGeometry args={[1.5, 8, 8]} />
            <meshLambertMaterial color={0x888888} transparent opacity={0.8} />
        </mesh>
    );
}

import React, { useRef, useEffect, useMemo } from 'react';
import * as THREE from 'three';
import { addObstacle, removeObstacle } from '../utils/collisionStore';
import { makeTextTexture } from './constants';

export function Godam({ x, z, type, rotationY = 0 }) {
    const godamRef = useRef();
    useEffect(() => {
        if (godamRef.current) addObstacle(godamRef.current);
        return () => { if (godamRef.current) removeObstacle(godamRef.current); };
    }, []);

    const w = 7.5, h = 4.5, d = 6, wallThick = 0.2;

    let signText = type === 'banana' ? "BANANA GODAM" : "CLOTHES GODAM";
    let signBg = type === 'banana' ? "#f39c12" : "#8e44ad";

    const signTex = useMemo(() => new THREE.CanvasTexture(makeTextTexture(signText, signBg, "#ffffff")), [signText, signBg]);

    const materials = useMemo(() => {
        return [
            <meshLambertMaterial attach="material-0" color={0x2c3e50} key="0" />,
            <meshLambertMaterial attach="material-1" color={0x2c3e50} key="1" />,
            <meshLambertMaterial attach="material-2" color={0x2c3e50} key="2" />,
            <meshLambertMaterial attach="material-3" color={0x2c3e50} key="3" />,
            <meshLambertMaterial attach="material-4" map={signTex} key="4" />,
            <meshLambertMaterial attach="material-5" color={0x2c3e50} key="5" />
        ];
    }, [signTex]);

    return (
        <group ref={godamRef} position={[x, 0, z]} rotation={[0, rotationY, 0]}>
            {/* Walls */}
            <mesh position={[0, h / 2, -d / 2 + wallThick / 2]} castShadow receiveShadow>
                <boxGeometry args={[w, h, wallThick]} />
                <meshLambertMaterial color={0x7f8c8d} />
            </mesh>
            <mesh position={[-w / 2 + wallThick / 2, h / 2, 0]} castShadow receiveShadow>
                <boxGeometry args={[wallThick, h, d]} />
                <meshLambertMaterial color={0x7f8c8d} />
            </mesh>
            <mesh position={[w / 2 - wallThick / 2, h / 2, 0]} castShadow receiveShadow>
                <boxGeometry args={[wallThick, h, d]} />
                <meshLambertMaterial color={0x7f8c8d} />
            </mesh>
            {/* Roof */}
            <mesh position={[0, h - wallThick / 2, 0]} castShadow receiveShadow>
                <boxGeometry args={[w, wallThick, d]} />
                <meshLambertMaterial color={0x34495e} />
            </mesh>
            {/* Sign */}
            <mesh position={[0, h + 0.6, d / 2 - 0.1]}>
                <boxGeometry args={[w - 0.5, 1.2, 0.2]} />
                {materials}
            </mesh>

            {/* Interiors */}
            {type === 'banana' ? <BananaGodamContent wallThick={wallThick} /> : <ClothesGodamContent wallThick={wallThick} />}
        </group>
    );
}

function BananaGodamContent({ wallThick }) {
    const content = [];
    for (let i = -2; i <= 2; i += 2) {
        for (let j = -2; j <= 1; j += 1.5) {
            content.push(
                <mesh key={`crate-${i}-${j}`} position={[i, 0.6 + wallThick, j]} castShadow>
                    <boxGeometry args={[1.5, 1.2, 1.2]} />
                    <meshLambertMaterial color={0x8b5a2b} />
                </mesh>
            );

            for (let b = -0.5; b <= 0.5; b += 0.5) {
                content.push(
                    <mesh key={`ban-${i}-${j}-${b}`} rotation={[Math.PI / 2, 0, Math.abs((i * 3 + j * 7)) % 2]} position={[i + b, 1.3, j]}>
                        <torusGeometry args={[0.3, 0.1, 8, 16, Math.PI]} />
                        <meshLambertMaterial color={0xffd700} />
                    </mesh>
                );
            }
        }
    }
    return <>{content}</>;
}

function ClothesGodamContent({ wallThick }) {
